import $ from 'jquery';

export default () => {
  $('.uploadfiles').each(function eachTypeFile() {
    const currentText = $(this).find('span').text();

    $(this).on('change', function uploudFile() {
      if ($(this).val().lastIndexOf('\\')) {
        var n = $(this).val().lastIndexOf('\\') + 1;
      } else {
        var n = $(this).val().lastIndexOf('/') + 1;
      }

      console.log('2');

      const fileName = $(this).val().slice(n);
      const inner = $(this).parent('.uploadfiles__box');
      const current = $(this).siblings('.uploadfiles__title').find('span');
      inner.addClass('added');

      current.text(fileName);
      if ($(this).val() === '') {
        current.text(currentText);
      }
    });
  })

  $('.discounts-block__add-button').on('click', ()=> {
    $('.discounts-popup').toggleClass('open');
  })

  $('.discounts-popup__close').on('click', ()=> {
    $('.discounts-popup').removeClass('open');
  })

  $('.orders-block__add-new').on('click', ()=> {
    $('.orders-popup').toggleClass('open');
  })

  $('.orders-popup__close').on('click', ()=> {
    $('.orders-popup').removeClass('open');
  })

  $('.show-password').on('click', function showPass() {
    const passInput = $(this).siblings('input[type="password"]');
    if ($(this).siblings('input').prop('type', 'password')) {
      passInput.prop('type', 'text')
    } else {
      passInput.prop('type', 'password');
    }
  })

  $('.add-site').on('click', () => {
    const id = Math.random();
    const input = `<input class="main-input" type="text" name="site_${id}" placeholder="Name or URL"></input>`;
    $('.site-box__list').append(input)
  })

  $('.area-mobile__nav-current').on('click', function openCloseMobileAreaNav() {
    $(this).toggleClass('active');
    $('.area-mobile__nav-list').slideToggle('500');
  })

  if (window.innerWidth < 767) {
    const headerStatus = $('.header-controls__status').html();
    const headerSettings = $('.header-controls__setting').html();
    const search = $('.search__form');

    $('.container-mobile').append(search);
    $('.container-mobile').append(`<div class="header-controls__status">${headerStatus}</div>`);
    $('.container-mobile').append(`<div class="header-controls__setting">${headerSettings}</div>`);
  }

  $('.search__button').on('click', (event) => {
    event.preventDefault();
    $('.search__input').toggleClass('open');
  })

  $(document).on('click touchstart', (e) => {
    if (!$(e.target).closest('.search__button, .search__input').length) {
      $('.search__input').removeClass('open');
    }
    e.stopPropagation();
  });

  $('.header-controls__link.comments').on('click', () => {
    $('.comments-popup').toggleClass('open');
  })

  $(document).on('click touchstart', (e) => {
    if (!$(e.target).closest('.header-controls__link.comments, .comments-popup').length) {
      $('.comments-popup').removeClass('open');
    }
    e.stopPropagation();
  });

  $('.header-controls__link.notifications').on('click', () => {
    $('.notifications-popup').toggleClass('open');
  })

  $(document).on('click touchstart', (e) => {
    if (!$(e.target).closest('.header-controls__link.notifications, .notifications-popup').length) {
      $('.notifications-popup').removeClass('open');
    }
    e.stopPropagation();
  });
}


