import $ from 'jquery';
import 'slick-carousel';
import 'social-likes';
import noUiSlider from 'nouislider';
import sliders from './components/sliders';
import "./markup-menu";
import Select from './components/select';
import Tabs from './components/tabs';
import main from './components/main';
import animations from './components/animations';
import popup from './components/popup';

global.$ = global.jQuery = $;
require('./components/accordion');
import datepicker from 'js-datepicker';
import chart from './components/chart';

document.addEventListener("DOMContentLoaded", () => {
  sliders();
  main();
  popup();
  chart();
  global.customeSelct = new Select();
  global.tabs = new Tabs({})
  if ($(window).width() < 1024) {
    const blogList = [];
    $('.blog-list__column').each(function() {
      blogList.push($(this).children());
    })
    $('.blog-list').html(blogList)
  }
  $('.range').each(function() {
    const element = $(this)
    const id  = $(this).attr('id');
    const min = +$(this).data('min');
    const max = +$(this).data('max');
    const step = +$(this).data('step');
    var slider = document.getElementById(id);
    noUiSlider.create(slider, {
      range: {
        'min': min,
        'max': max
      },
      start: min,
      connect: [true, false],
      step: step,
      format: {
        to: function(value) {
          return +value
        },
        from: function (value) {
          return value.replace(',-', '');
      }
      },
      pips: {
          mode: 'count',
          values: 20,
          density: 40,
          stepped: true
      }
  });
  slider.noUiSlider.on('slide', function(values, handle) {
    console.log(values[0])
    element.find('.noUi-marker').removeClass('current');
    element.find('.noUi-marker').eq(values[0] / step).addClass('current');
    element.find('.noUi-value').removeClass('current');
    element.find('.noUi-value').eq(values[0] / step).addClass('current');
  });
  });
  $('.burger').on('click', ()=> {
    $('.menu').addClass('active');
  })
  $('.menu-close').on('click', ()=> {
    $('.menu').removeClass('active');
  })
  if ($(window).width() < 901) {
    $('.menu').prepend($('.navigation'));
    $('.menu').append($('.footer-item.stats'));
  }
  if ($(window).width() < 768) {
    $('.menu').append($('.header-account .row'))
  }
  $(window).on('resize', ()=> {
    if ($(window).width() < 901) {
      $('.menu').prepend($('.navigation'));
      $('.menu').append($('.footer-item.stats'));
    } else {
      $('.header-account').before($('.navigation'));
    }
    if ($(window).width() < 768) {
      $('.menu').append($('.header-account .row'))
    } else {
      $('.footer-holder .container').append($('.footer-item.stats'));
    }
  })
  $('.to-top').click(function(){
      $("html, body").animate({ scrollTop: 0 }, 600);
      return false;
  });

  if ($('#date_from').length && $('#date_to').length ) {
    const dateStart = Date.now();
    const pickerstart = datepicker('#date_from', { 
      startDay: 1,
      formatter: (input, date) => {
        const value = date.toLocaleDateString()
        input.value = value
      },
      id: 1,
      disabler: date => (date <= dateStart),
      onSelect: (instance, selectedDate) => {
        instance.setMin(selectedDate);
      }
    })

    const pickerend = datepicker('#date_to', { 
      startDay: 1,
      formatter: (input, date) => {
        const value = date.toLocaleDateString()
        input.value = value
      },
      id: 1,
      onSelect: (instance, selectedDate) => {
        instance.setMax(selectedDate);
      }
    })
  };
  $(".anchor").on("click", function (event) {
		event.preventDefault();
		var id  = $(this).attr('href'),
			top = $(id).offset().top;
		$('body,html').animate({scrollTop: top}, 900);
  });
  $('.order-item a').on('click', function() {
    $('.order-item').removeClass('active');
    $(this).parents('.order-item').addClass('active');
  });
  $('.next-step-btn').on('click', function(){
    $(this).parents('.order-step').removeClass('active')
    $(this).parents('.order-step').find('.slide').slideToggle();
    $(this).parents('.order-step').next().find('.slide').slideToggle();
    $(this).parents('.order-step').next().addClass('active');
  })
})



